import { Component, ElementRef, OnDestroy, OnInit, ViewChild } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormArray, FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Subject, startWith, takeUntil } from 'rxjs';

type ProductType = 'fenetre' | 'porte' | 'box' | 'custom';
type ToolMode = 'select' | 'addV' | 'addH';

interface SerieDef {
  id: string;
  nom: string;
  longueurBarreCm: number;
  prixBarre: number;
}

interface VBar {
  id: string;
  xCm: number;
  serieId: string;
}

interface HBar {
  id: string;
  yCm: number;
  serieId: string;
}

interface AccessoryFormValue {
  designation?: string | null;
  quantite?: number | null;
  prixUnitaire?: number | null;
}

interface SerieResult {
  id: string;
  nom: string;
  longueurPiecesCm: number;
  pertesCm: number;
  consommationCm: number;
  nbBarres: number;
  longueurAcheteeCm: number;
  chuteCm: number;
  cout: number;
}

interface EstimationResult {
  consommationTotaleCm: number;
  longueurAcheteeTotaleCm: number;
  chuteTotaleCm: number;
  coutBarres: number;

  surfaceVerreM2: number;
  coutVerre: number;

  coutAccessoires: number;
  coutTotal: number;

  series: SerieResult[];
}

@Component({
  selector: 'app-estimation',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './estimation.component.html',
  styleUrls: ['./estimation.component.css']
})
export class EstimationComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  @ViewChild('planSvg') planSvg?: ElementRef<SVGSVGElement>;

  tool: ToolMode = 'select';
  selected: { kind: 'v' | 'h'; id: string } | null = null;
  private dragging: { kind: 'v' | 'h'; id: string; pointerId: number } | null = null;

  // IDs “protégés”
  private readonly ID_S40 = 's40';
  private readonly ID_S76 = 's76';
  private readonly ID_PARCLOSE = 'parclose';

  form = this.fb.group({
    produit: this.fb.group({
      type: ['fenetre' as ProductType],
      largeurCm: [120, [Validators.required, Validators.min(10)]],
      hauteurCm: [100, [Validators.required, Validators.min(10)]],
      profondeurCm: [40, [Validators.min(0)]],
      cadreRenfort: [false],
      cadreSerieId: [this.ID_S40, Validators.required]
    }),

    series: this.fb.array([]),

    // barres dessinées
    montants: this.fb.array([]),
    traverses: this.fb.array([]),

    options: this.fb.group({
      margeChute: [0],
      pertesCoupeCm: [0.2]
    }),

    verre: this.fb.group({
      activerVerre: [false],
      prixVerreM2: [0]
    }),

    accessoires: this.fb.array([])
  });

  result: EstimationResult = {
    consommationTotaleCm: 0,
    longueurAcheteeTotaleCm: 0,
    chuteTotaleCm: 0,
    coutBarres: 0,
    surfaceVerreM2: 0,
    coutVerre: 0,
    coutAccessoires: 0,
    coutTotal: 0,
    series: []
  };

  constructor(private fb: FormBuilder) {
    // séries par défaut : 40 / 76 / Parclose
    this.series.push(this.createSerie({ id: this.ID_S40, nom: 'Série 40', longueurBarreCm: 630, prixBarre: 0 }));
    this.series.push(this.createSerie({ id: this.ID_S76, nom: 'Série 76', longueurBarreCm: 630, prixBarre: 0 }));
    this.series.push(this.createSerie({ id: this.ID_PARCLOSE, nom: 'Parclose', longueurBarreCm: 630, prixBarre: 0 }));
  }

  ngOnInit(): void {
    this.form.valueChanges
      .pipe(startWith(this.form.getRawValue()), takeUntil(this.destroy$))
      .subscribe(() => this.compute());

    this.compute();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  // ---------- getters ----------
  get series(): FormArray {
    return this.form.get('series') as FormArray;
  }

  get montants(): FormArray {
    return this.form.get('montants') as FormArray;
  }

  get traverses(): FormArray {
    return this.form.get('traverses') as FormArray;
  }

  get accessoires(): FormArray {
    return this.form.get('accessoires') as FormArray;
  }

  get productType(): ProductType {
    return (this.form.get('produit.type')?.value as ProductType) ?? 'fenetre';
  }

  get widthCm(): number {
    return Math.max(10, this.toNumber(this.form.get('produit.largeurCm')?.value));
  }

  get heightCm(): number {
    return Math.max(10, this.toNumber(this.form.get('produit.hauteurCm')?.value));
  }

  get toolLabel(): string {
    if (this.tool === 'select') return 'Sélection';
    if (this.tool === 'addV') return 'Ajout montant vertical';
    return 'Ajout traverse horizontale';
  }

  get seriesForProfiles(): { id: string; nom: string }[] {
    // Série 40 & 76 seulement pour profils (parclose est calculée automatiquement)
    const defs = (this.series.getRawValue() as SerieDef[]) ?? [];
    return defs
      .filter(s => s.id !== this.ID_PARCLOSE)
      .map(s => ({ id: s.id, nom: s.nom || s.id }));
  }

  get verticalBars(): VBar[] {
    const raw = (this.montants.getRawValue() as VBar[]) ?? [];
    return raw
      .map(b => ({ ...b, xCm: this.round1(this.toNumber(b.xCm)) }))
      .sort((a, b) => a.xCm - b.xCm);
  }

  get horizontalBars(): HBar[] {
    const raw = (this.traverses.getRawValue() as HBar[]) ?? [];
    return raw
      .map(b => ({ ...b, yCm: this.round1(this.toNumber(b.yCm)) }))
      .sort((a, b) => a.yCm - b.yCm);
  }

  // ---------- series ----------
  addSerie(): void {
    this.series.push(this.createSerie({ nom: 'Nouvelle série', longueurBarreCm: 630, prixBarre: 0 }));
  }

  removeSerie(index: number): void {
    if (this.isProtectedSerie(index)) return;
    const removedId = (this.series.at(index).value as SerieDef)?.id;
    this.series.removeAt(index);

    // si une barre utilisait la série supprimée, basculer vers s40
    const fallback = this.ID_S40;
    this.montants.controls.forEach(c => {
      if (c.get('serieId')?.value === removedId) c.get('serieId')?.setValue(fallback);
    });
    this.traverses.controls.forEach(c => {
      if (c.get('serieId')?.value === removedId) c.get('serieId')?.setValue(fallback);
    });
  }

  isProtectedSerie(index: number): boolean {
    const id = (this.series.at(index).value as SerieDef)?.id;
    return id === this.ID_S40 || id === this.ID_S76 || id === this.ID_PARCLOSE;
  }

  private createSerie(initial?: Partial<SerieDef>): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [initial?.id ?? this.createId('serie')],
      nom: [initial?.nom ?? 'Série', Validators.required],
      longueurBarreCm: [initial?.longueurBarreCm ?? 630, [Validators.required, Validators.min(10)]],
      prixBarre: [initial?.prixBarre ?? 0, [Validators.min(0)]]
    });
  }

  // ---------- accessories ----------
  addAccessory(): void {
    this.accessoires.push(this.createAccessory());
  }

  removeAccessory(index: number): void {
    this.accessoires.removeAt(index);
  }

  private createAccessory(): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      designation: [''],
      quantite: [1, [Validators.min(0)]],
      prixUnitaire: [0, [Validators.min(0)]]
    });
  }

  // ---------- drawing tools ----------
  setTool(mode: ToolMode): void {
    this.tool = mode;
  }

  clearBars(): void {
    this.selected = null;
    this.dragging = null;
    this.montants.clear();
    this.traverses.clear();
  }

  onPlanClick(evt: MouseEvent): void {
    if (this.tool === 'select') {
      this.selected = null;
      return;
    }

    const p = this.toSvgPoint(evt);
    const w = this.widthCm;
    const h = this.heightCm;

    if (this.tool === 'addV') {
      const x = this.clamp(this.round1(p.x), 1, w - 1);
      this.montants.push(this.createVBar({ xCm: x, serieId: this.ID_S40 }));
    }

    if (this.tool === 'addH') {
      const y = this.clamp(this.round1(p.y), 1, h - 1);
      this.traverses.push(this.createHBar({ yCm: y, serieId: this.ID_S40 }));
    }
  }

  onBarPointerDown(kind: 'v' | 'h', id: string, evt: PointerEvent): void {
    evt.stopPropagation();
    evt.preventDefault();

    this.selected = { kind, id };
    this.dragging = { kind, id, pointerId: evt.pointerId };

    // pointer capture
    try {
      (evt.target as any)?.setPointerCapture?.(evt.pointerId);
    } catch {}
  }

  onPlanPointerMove(evt: PointerEvent): void {
    if (!this.dragging) return;

    const p = this.toSvgPoint(evt);
    const w = this.widthCm;
    const h = this.heightCm;

    if (this.dragging.kind === 'v') {
      const x = this.clamp(this.round1(p.x), 1, w - 1);
      this.setVBarX(this.dragging.id, x, false);
    } else {
      const y = this.clamp(this.round1(p.y), 1, h - 1);
      this.setHBarY(this.dragging.id, y, false);
    }
  }

  onPlanPointerUp(_evt: PointerEvent): void {
    this.dragging = null;
  }

  removeSelected(): void {
    if (!this.selected) return;
    const { kind, id } = this.selected;
    if (kind === 'v') this.removeVBar(id);
    else this.removeHBar(id);
    this.selected = null;
  }

  // ---------- edit helpers (panel) ----------
  getVBar(id: string): VBar | null {
    return this.verticalBars.find(b => b.id === id) ?? null;
  }

  getHBar(id: string): HBar | null {
    return this.horizontalBars.find(b => b.id === id) ?? null;
  }

  updateVBarX(id: string, value: any): void {
    const x = this.clamp(this.round1(this.toNumber(value)), 1, this.widthCm - 1);
    this.setVBarX(id, x, true);
  }

  updateHBarY(id: string, value: any): void {
    const y = this.clamp(this.round1(this.toNumber(value)), 1, this.heightCm - 1);
    this.setHBarY(id, y, true);
  }

  updateVBarSerie(id: string, serieId: string): void {
    const i = this.findIndexById(this.montants, id);
    if (i < 0) return;
    this.montants.at(i).get('serieId')?.setValue(serieId);
  }

  updateHBarSerie(id: string, serieId: string): void {
    const i = this.findIndexById(this.traverses, id);
    if (i < 0) return;
    this.traverses.at(i).get('serieId')?.setValue(serieId);
  }

  private setVBarX(id: string, x: number, emit: boolean): void {
    const i = this.findIndexById(this.montants, id);
    if (i < 0) return;
    this.montants.at(i).get('xCm')?.setValue(x, { emitEvent: emit });
  }

  private setHBarY(id: string, y: number, emit: boolean): void {
    const i = this.findIndexById(this.traverses, id);
    if (i < 0) return;
    this.traverses.at(i).get('yCm')?.setValue(y, { emitEvent: emit });
  }

  private removeVBar(id: string): void {
    const i = this.findIndexById(this.montants, id);
    if (i >= 0) this.montants.removeAt(i);
  }

  private removeHBar(id: string): void {
    const i = this.findIndexById(this.traverses, id);
    if (i >= 0) this.traverses.removeAt(i);
  }

  private createVBar(initial?: Partial<VBar>): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [initial?.id ?? this.createId('v')],
      xCm: [initial?.xCm ?? 0, [Validators.required, Validators.min(0)]],
      serieId: [initial?.serieId ?? this.ID_S40, Validators.required]
    });
  }

  private createHBar(initial?: Partial<HBar>): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [initial?.id ?? this.createId('h')],
      yCm: [initial?.yCm ?? 0, [Validators.required, Validators.min(0)]],
      serieId: [initial?.serieId ?? this.ID_S40, Validators.required]
    });
  }

  // ---------- template generator ----------
  applyTemplate(): void {
    const raw = this.form.getRawValue();
    const type = (raw.produit?.type as ProductType) ?? 'fenetre';
    const h = this.heightCm;

    this.clearBars();

    if (type === 'fenetre') {
      // rien
      return;
    }

    if (type === 'porte') {
      if (raw.produit?.cadreRenfort) {
        this.traverses.push(this.createHBar({ yCm: this.round1(h / 2), serieId: this.ID_S40 }));
      }
      return;
    }

    if (type === 'box') {
      // V1: rien (tu peux dessiner à la main)
      return;
    }

    if (type === 'custom') {
      return;
    }
  }

  // ---------- reset / print ----------
  reset(): void {
    this.form.reset({
      produit: {
        type: 'fenetre',
        largeurCm: 120,
        hauteurCm: 100,
        profondeurCm: 40,
        cadreRenfort: false,
        cadreSerieId: this.ID_S40
      },
      options: {
        margeChute: 0,
        pertesCoupeCm: 0.2
      },
      verre: {
        activerVerre: false,
        prixVerreM2: 0
      },
      accessoires: []
    });

    // reset barres
    this.clearBars();

    // reset accessoires
    this.accessoires.clear();

    // reset prix séries (mais garder 40/76/parclose)
    const defs = (this.series.getRawValue() as SerieDef[]) ?? [];
    this.series.clear();
    this.series.push(this.createSerie({ id: this.ID_S40, nom: 'Série 40', longueurBarreCm: 630, prixBarre: defs.find(x => x.id === this.ID_S40)?.prixBarre ?? 0 }));
    this.series.push(this.createSerie({ id: this.ID_S76, nom: 'Série 76', longueurBarreCm: 630, prixBarre: defs.find(x => x.id === this.ID_S76)?.prixBarre ?? 0 }));
    this.series.push(this.createSerie({ id: this.ID_PARCLOSE, nom: 'Parclose', longueurBarreCm: 630, prixBarre: defs.find(x => x.id === this.ID_PARCLOSE)?.prixBarre ?? 0 }));

    this.compute();
  }

  print(): void {
    window.print();
  }

  // ---------- compute ----------
  compute(): void {
    const raw = this.form.getRawValue();

    const width = this.widthCm;
    const height = this.heightCm;

    // clamp positions silently if dimensions changed
    this.sanitizeBars(width, height);

    const margeChuteRate = Math.max(0, this.toNumber(raw.options?.margeChute)) / 100;
    const pertesCoupeCm = Math.max(0, this.toNumber(raw.options?.pertesCoupeCm));

    const seriesDefs = ((raw.series ?? []) as SerieDef[]).map(s => ({
      id: s.id,
      nom: (s.nom ?? '').trim() || s.id,
      longueurBarreCm: Math.max(0, this.toNumber(s.longueurBarreCm)),
      prixBarre: Math.max(0, this.toNumber(s.prixBarre))
    }));

    const cadreSerieId = (raw.produit?.cadreSerieId as string) ?? this.ID_S40;

    const vBars = this.verticalBars;
    const hBars = this.horizontalBars;

    // ----- agrégation longueur/pièces par série
    const agg = new Map<string, { lengthCm: number; pieces: number }>();
    const add = (serieId: string, lengthCm: number, pieces: number) => {
      if (!serieId) return;
      const prev = agg.get(serieId) ?? { lengthCm: 0, pieces: 0 };
      agg.set(serieId, { lengthCm: prev.lengthCm + lengthCm, pieces: prev.pieces + pieces });
    };

    // cadre extérieur = 4 pièces
    add(cadreSerieId, 2 * height + 2 * width, 4);

    // montants = 1 pièce chacun (longueur = hauteur)
    vBars.forEach(b => add(b.serieId, height, 1));

    // traverses = 1 pièce chacune (longueur = largeur)
    hBars.forEach(b => add(b.serieId, width, 1));

    // verre + parclose
    const activerVerre = !!raw.verre?.activerVerre;

    // surface verre en m² (cm² -> m²)
    const surfaceVerreM2 = (width * height) / 10000;
    const prixVerreM2 = Math.max(0, this.toNumber(raw.verre?.prixVerreM2));
    const coutVerre = activerVerre ? surfaceVerreM2 * prixVerreM2 : 0;

    if (activerVerre) {
      // parclose = somme des périmètres des vitrages découpés par la grille
      const xs = [0, ...vBars.map(b => b.xCm), width].sort((a, b) => a - b);
      const ys = [0, ...hBars.map(b => b.yCm), height].sort((a, b) => a - b);

      const unique = (arr: number[]) => arr.filter((v, i) => i === 0 || Math.abs(v - arr[i - 1]) > 0.001);
      const ux = unique(xs);
      const uy = unique(ys);

      let parcloseLength = 0;
      let paneCount = 0;

      for (let i = 0; i < ux.length - 1; i++) {
        for (let j = 0; j < uy.length - 1; j++) {
          const wPane = Math.max(0, ux[i + 1] - ux[i]);
          const hPane = Math.max(0, uy[j + 1] - uy[j]);
          if (wPane <= 0 || hPane <= 0) continue;

          paneCount++;
          parcloseLength += 2 * (wPane + hPane); // périmètre
        }
      }

      // parclose = 4 pièces par vitrage (2 horizontales + 2 verticales)
      const parclosePieces = paneCount * 4;
      add(this.ID_PARCLOSE, parcloseLength, parclosePieces);
    } else {
      // si pas de verre => pas de parclose
      add(this.ID_PARCLOSE, 0, 0);
    }

    // ----- calcul résultats par série
    const seriesResults: SerieResult[] = seriesDefs.map(s => {
      const base = agg.get(s.id)?.lengthCm ?? 0;
      const pieces = agg.get(s.id)?.pieces ?? 0;

      const pertes = pieces * pertesCoupeCm;
      const consommation = (base + pertes) * (1 + margeChuteRate);

      const nbBarres = (s.longueurBarreCm > 0 && consommation > 0)
        ? Math.ceil(consommation / s.longueurBarreCm)
        : 0;

      const longueurAchetee = nbBarres * s.longueurBarreCm;
      const chute = Math.max(0, longueurAchetee - consommation);
      const cout = nbBarres * s.prixBarre;

      return {
        id: s.id,
        nom: s.nom,
        longueurPiecesCm: this.round2(base),
        pertesCm: this.round2(pertes),
        consommationCm: this.round2(consommation),
        nbBarres,
        longueurAcheteeCm: this.round2(longueurAchetee),
        chuteCm: this.round2(chute),
        cout: this.round2(cout)
      };
    });

    const consommationTotaleCm = this.round2(seriesResults.reduce((sum, r) => sum + r.consommationCm, 0));
    const longueurAcheteeTotaleCm = this.round2(seriesResults.reduce((sum, r) => sum + r.longueurAcheteeCm, 0));
    const chuteTotaleCm = this.round2(seriesResults.reduce((sum, r) => sum + r.chuteCm, 0));
    const coutBarres = this.round2(seriesResults.reduce((sum, r) => sum + r.cout, 0));

    // accessoires
    const accessoires = (raw.accessoires ?? []) as AccessoryFormValue[];
    const coutAccessoires = accessoires.reduce((sum, a) => {
      const q = Math.max(0, this.toNumber(a.quantite));
      const pu = Math.max(0, this.toNumber(a.prixUnitaire));
      return sum + q * pu;
    }, 0);

    const coutTotal = coutBarres + coutVerre + coutAccessoires;

    this.result = {
      consommationTotaleCm,
      longueurAcheteeTotaleCm,
      chuteTotaleCm,
      coutBarres,
      surfaceVerreM2: this.round2(surfaceVerreM2),
      coutVerre: this.round2(coutVerre),
      coutAccessoires: this.round2(coutAccessoires),
      coutTotal: this.round2(coutTotal),
      series: seriesResults
    };
  }

  // ---------- helpers ----------
  private sanitizeBars(width: number, height: number): void {
    // clamp montants
    this.montants.controls.forEach(ctrl => {
      const xCtrl = ctrl.get('xCm');
      if (!xCtrl) return;
      const x = this.round1(this.toNumber(xCtrl.value));
      const clamped = this.clamp(x, 1, width - 1);
      if (Math.abs(clamped - x) > 0.0001) xCtrl.setValue(clamped, { emitEvent: false });
    });

    // clamp traverses
    this.traverses.controls.forEach(ctrl => {
      const yCtrl = ctrl.get('yCm');
      if (!yCtrl) return;
      const y = this.round1(this.toNumber(yCtrl.value));
      const clamped = this.clamp(y, 1, height - 1);
      if (Math.abs(clamped - y) > 0.0001) yCtrl.setValue(clamped, { emitEvent: false });
    });
  }

  private findIndexById(arr: FormArray, id: string): number {
    return arr.controls.findIndex(c => c.get('id')?.value === id);
  }

  private toSvgPoint(evt: MouseEvent | PointerEvent): { x: number; y: number } {
    const svg = this.planSvg?.nativeElement;
    if (!svg) return { x: 0, y: 0 };

    const pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;

    const ctm = svg.getScreenCTM();
    if (!ctm) return { x: 0, y: 0 };

    const sp = pt.matrixTransform(ctm.inverse());
    return { x: sp.x, y: sp.y };
  }

  private toNumber(v: unknown): number {
    const n = Number(v);
    return Number.isFinite(n) ? n : 0;
  }

  private round1(n: number): number {
    return Math.round((n + Number.EPSILON) * 10) / 10;
  }

  private round2(n: number): number {
    return Math.round((n + Number.EPSILON) * 100) / 100;
  }

  private clamp(n: number, min: number, max: number): number {
    if (max < min) return min;
    return Math.max(min, Math.min(max, n));
  }

  private createId(prefix: string): string {
    return globalThis.crypto?.randomUUID?.() ?? `${prefix}_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  }
}
<section class="panel">
  <div class="panel-header">
    <div>
      <h1>Estimation de prix</h1>
      <p>Dessinez (simplement) le produit en cm et calculez le coût total.</p>
    </div>
    <div class="panel-actions no-print">
      <button class="btn ghost" type="button" (click)="reset()">Réinitialiser</button>
      <button class="btn primary" type="button" (click)="print()">Imprimer estimation</button>
    </div>
  </div>

  <form class="estimation-grid" [formGroup]="form">

    <!-- =======================
         PRODUIT / DIMENSIONS (cm)
    ======================== -->
    <section class="card">
      <h2>Produit à fabriquer (cm)</h2>

      <div class="grid-3" formGroupName="produit">
        <label class="field">
          <span>Type</span>
          <select class="input" formControlName="type">
            <option value="fenetre">Fenêtre</option>
            <option value="porte">Porte</option>
            <option value="box">Box</option>
            <option value="custom">Custom</option>
          </select>
        </label>

        <label class="field">
          <span>Largeur (cm)</span>
          <input class="input" type="number" min="10" step="0.1" formControlName="largeurCm">
        </label>

        <label class="field">
          <span>Hauteur (cm)</span>
          <input class="input" type="number" min="10" step="0.1" formControlName="hauteurCm">
        </label>

        <label class="field" *ngIf="productType === 'box'">
          <span>Profondeur (cm)</span>
          <input class="input" type="number" min="0" step="0.1" formControlName="profondeurCm">
        </label>

        <label class="field checkbox" *ngIf="productType === 'porte'">
          <input type="checkbox" formControlName="cadreRenfort">
          <span>Ajouter renfort (traverse)</span>
        </label>

        <label class="field">
          <span>Série du cadre extérieur</span>
          <select class="input" formControlName="cadreSerieId">
            <option *ngFor="let s of seriesForProfiles" [value]="s.id">{{ s.nom }}</option>
          </select>
        </label>

        <div class="field no-print">
          <span>&nbsp;</span>
          <button class="btn outline" type="button" (click)="applyTemplate()">
            Générer modèle
          </button>
        </div>
      </div>

      <div class="hint">
        Le plan ci-dessous représente le cadre (largeur/hauteur). Ajoute des montants/traverses pour découper le vitrage.
      </div>
    </section>

    <!-- =======================
         SERIES (40 / 76 / PARCLOSE)
    ======================== -->
    <section class="card">
      <div class="section-head">
        <h2>Séries & barres (cm)</h2>
        <button class="btn outline no-print" type="button" (click)="addSerie()">Ajouter série</button>
      </div>

      <div class="series" formArrayName="series">
        <div class="series-row series-head">
          <div>Nom</div>
          <div>Longueur barre (cm)</div>
          <div>Prix barre (DT)</div>
          <div></div>
        </div>

        <div
          class="series-row"
          *ngFor="let s of series.controls; let i = index"
          [formGroupName]="i"
        >
          <input class="input" formControlName="nom" placeholder="Série 40">
          <input class="input" type="number" min="10" step="0.1" formControlName="longueurBarreCm">
          <input class="input" type="number" min="0" step="0.01" formControlName="prixBarre">
          <button
            class="btn danger no-print"
            type="button"
            (click)="removeSerie(i)"
            [disabled]="isProtectedSerie(i)"
          >
            Supprimer
          </button>
        </div>

        <div class="hint">
          Exemple : barre de 6m30 = <strong>630 cm</strong>.
          Parclose est calculée automatiquement (si vitrage activé).
        </div>
      </div>
    </section>

    <!-- =======================
         DESIGNER (SVG)
    ======================== -->
    <section class="card">
      <div class="section-head">
        <h2>Plan (dessin simple)</h2>

        <div class="designer-toolbar no-print">
          <button class="btn outline" type="button" [class.active]="tool==='select'" (click)="setTool('select')">
            Sélection
          </button>
          <button class="btn outline" type="button" [class.active]="tool==='addV'" (click)="setTool('addV')">
            + Montant vertical
          </button>
          <button class="btn outline" type="button" [class.active]="tool==='addH'" (click)="setTool('addH')">
            + Traverse horizontale
          </button>
          <button class="btn ghost" type="button" (click)="clearBars()">
            Vider
          </button>
        </div>
      </div>

      <div class="designer-wrap">
        <div class="plan-area">
          <svg
            #planSvg
            class="plan-svg"
            [attr.viewBox]="'0 0 ' + widthCm + ' ' + heightCm"
            preserveAspectRatio="xMidYMid meet"
            (click)="onPlanClick($event)"
            (pointermove)="onPlanPointerMove($event)"
            (pointerup)="onPlanPointerUp($event)"
            (pointerleave)="onPlanPointerUp($event)"
          >
            <!-- cadre -->
            <rect
              x="0" y="0"
              [attr.width]="widthCm"
              [attr.height]="heightCm"
              class="frame"
            ></rect>

            <!-- montants -->
            <line
              *ngFor="let b of verticalBars"
              class="bar"
              [class.selected]="selected?.kind==='v' && selected?.id===b.id"
              [attr.x1]="b.xCm" [attr.y1]="0"
              [attr.x2]="b.xCm" [attr.y2]="heightCm"
              (pointerdown)="onBarPointerDown('v', b.id, $event)"
            ></line>

            <!-- traverses -->
            <line
              *ngFor="let b of horizontalBars"
              class="bar"
              [class.selected]="selected?.kind==='h' && selected?.id===b.id"
              [attr.x1]="0" [attr.y1]="b.yCm"
              [attr.x2]="widthCm" [attr.y2]="b.yCm"
              (pointerdown)="onBarPointerDown('h', b.id, $event)"
            ></line>
          </svg>

          <div class="hint">
            Mode <strong>{{ toolLabel }}</strong> — Cliquez pour ajouter. Glissez une barre pour la déplacer.
          </div>
        </div>

        <!-- panneau édition (si sélection) -->
        <div class="edit-area no-print" *ngIf="selected as sel">
          <h3>Élément sélectionné</h3>

          <div class="grid-2" *ngIf="sel.kind==='v'">
            <label class="field">
              <span>Position X (cm)</span>
              <input class="input" type="number" min="0" step="0.1"
                     [value]="getVBar(sel.id)?.xCm"
                     (input)="updateVBarX(sel.id, $any($event.target).value)">
            </label>

            <label class="field">
              <span>Série</span>
              <select class="input"
                      [value]="getVBar(sel.id)?.serieId"
                      (change)="updateVBarSerie(sel.id, $any($event.target).value)">
                <option *ngFor="let s of seriesForProfiles" [value]="s.id">{{ s.nom }}</option>
              </select>
            </label>
          </div>

          <div class="grid-2" *ngIf="sel.kind==='h'">
            <label class="field">
              <span>Position Y (cm)</span>
              <input class="input" type="number" min="0" step="0.1"
                     [value]="getHBar(sel.id)?.yCm"
                     (input)="updateHBarY(sel.id, $any($event.target).value)">
            </label>

            <label class="field">
              <span>Série</span>
              <select class="input"
                      [value]="getHBar(sel.id)?.serieId"
                      (change)="updateHBarSerie(sel.id, $any($event.target).value)">
                <option *ngFor="let s of seriesForProfiles" [value]="s.id">{{ s.nom }}</option>
              </select>
            </label>
          </div>

          <button class="btn danger" type="button" (click)="removeSelected()">
            Supprimer l’élément
          </button>
        </div>
      </div>
    </section>

    <!-- =======================
         OPTIONS COUPE (cm)
    ======================== -->
    <section class="card">
      <h2>Options de coupe</h2>
      <div class="grid-2" formGroupName="options">
        <label class="field">
          <span>Marge chute (%)</span>
          <input class="input" type="number" min="0" step="0.1" formControlName="margeChute">
        </label>
        <label class="field">
          <span>Pertes par coupe (cm)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="pertesCoupeCm">
        </label>
      </div>
      <div class="hint">
        Les pertes sont appliquées sur le nombre de pièces (cadre + montants + traverses + parcloses).
      </div>
    </section>

    <!-- =======================
         VERRE
    ======================== -->
    <section class="card">
      <h2>Verre</h2>
      <div class="grid-2" formGroupName="verre">
        <label class="field checkbox">
          <input type="checkbox" formControlName="activerVerre">
          <span>Inclure le vitrage (active aussi la parclose)</span>
        </label>
        <label class="field">
          <span>Prix verre (DT/m²)</span>
          <input class="input" type="number" min="0" step="0.01" formControlName="prixVerreM2">
        </label>
      </div>

      <div class="hint">
        Surface verre estimée : <strong>{{ result.surfaceVerreM2 | number:'1.2-2' }} m²</strong>
      </div>
    </section>

    <!-- =======================
         ACCESSOIRES
    ======================== -->
    <section class="card">
      <div class="section-head">
        <h2>Accessoires</h2>
        <button class="btn outline no-print" type="button" (click)="addAccessory()">Ajouter accessoire</button>
      </div>

      <div class="accessories" formArrayName="accessoires">
        <div class="accessory-row accessory-head">
          <div>Désignation</div>
          <div>Qté</div>
          <div>PU (DT)</div>
          <div></div>
        </div>

        <div
          class="accessory-row"
          *ngFor="let acc of accessoires.controls; let i = index"
          [formGroupName]="i"
        >
          <input class="input" formControlName="designation" placeholder="Poignée, visserie...">
          <input class="input" type="number" min="0" step="1" formControlName="quantite">
          <input class="input" type="number" min="0" step="0.01" formControlName="prixUnitaire">
          <button class="btn danger no-print" type="button" (click)="removeAccessory(i)">Supprimer</button>
        </div>

        <div class="empty" *ngIf="accessoires.length === 0">
          Aucun accessoire ajouté.
        </div>
      </div>
    </section>

    <!-- =======================
         RESULTS
    ======================== -->
    <section class="card results">
      <h2>Résultats</h2>

      <div class="results-grid">
        <div>
          <span>Conso totale</span>
          <strong>{{ result.consommationTotaleCm | number:'1.2-2' }} cm</strong>
        </div>
        <div>
          <span>Longueur achetée totale</span>
          <strong>{{ result.longueurAcheteeTotaleCm | number:'1.2-2' }} cm</strong>
        </div>
        <div>
          <span>Chute totale</span>
          <strong>{{ result.chuteTotaleCm | number:'1.2-2' }} cm</strong>
        </div>
        <div>
          <span>Coût barres</span>
          <strong>{{ result.coutBarres | number:'1.2-2' }} DT</strong>
        </div>
        <div>
          <span>Coût verre</span>
          <strong>{{ result.coutVerre | number:'1.2-2' }} DT</strong>
        </div>
        <div>
          <span>Coût accessoires</span>
          <strong>{{ result.coutAccessoires | number:'1.2-2' }} DT</strong>
        </div>
        <div class="grand-total">
          <span>Coût total</span>
          <strong>{{ result.coutTotal | number:'1.2-2' }} DT</strong>
        </div>
      </div>

      <h3 class="sub-title">Détail par série</h3>
      <table class="breakdown" *ngIf="result.series.length > 0">
        <thead>
          <tr>
            <th>Série</th>
            <th class="num">Pièces (cm)</th>
            <th class="num">Pertes (cm)</th>
            <th class="num">Conso (cm)</th>
            <th class="num">Nb barres</th>
            <th class="num">Acheté (cm)</th>
            <th class="num">Chute (cm)</th>
            <th class="num">Coût (DT)</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let s of result.series">
            <td>{{ s.nom }}</td>
            <td class="num">{{ s.longueurPiecesCm | number:'1.2-2' }}</td>
            <td class="num">{{ s.pertesCm | number:'1.2-2' }}</td>
            <td class="num">{{ s.consommationCm | number:'1.2-2' }}</td>
            <td class="num">{{ s.nbBarres }}</td>
            <td class="num">{{ s.longueurAcheteeCm | number:'1.2-2' }}</td>
            <td class="num">{{ s.chuteCm | number:'1.2-2' }}</td>
            <td class="num">{{ s.cout | number:'1.2-2' }}</td>
          </tr>
        </tbody>
      </table>
    </section>
  </form>
</section>
